import hashlib
import secrets
from typing import Dict, List, Tuple
from dataclasses import dataclass
from datetime import datetime
import logging

@dataclass
class Transaction:
    transaction_id: str
    account_id: str
    amount: float
    transaction_type: str  # 'debit' or 'credit'
    timestamp: datetime
    description: str = ""

@dataclass
class Account:
    account_id: str
    balance: float
    currency: str = "USD"
    created_at: datetime = None

class FinancialProcessor:
    def __init__(self):
        self.accounts: Dict[str, Account] = {}
        self.transactions: List[Transaction] = []
        self._logger = self._setup_logger()
        
    def _setup_logger(self) -> logging.Logger:
        logger = logging.getLogger("FinancialProcessor")
        logger.setLevel(logging.INFO)
        handler = logging.StreamHandler()
        formatter = logging.Formatter(
            '%(asctime)s - %(name)s - %(levelname)s - %(message)s'
        )
        handler.setFormatter(formatter)
        logger.addHandler(handler)
        return logger
    
    def _validate_account_id(self, account_id: str) -> bool:
        if not isinstance(account_id, str) or not account_id.strip():
            return False
        return True
    
    def _validate_amount(self, amount: float) -> bool:
        if not isinstance(amount, (int, float)):
            return False
        if amount <= 0:
            return False
        return True
    
    def _validate_transaction_type(self, transaction_type: str) -> bool:
        return transaction_type.lower() in ['debit', 'credit']
    
    def _generate_transaction_id(self) -> str:
        return hashlib.sha256(
            f"{secrets.token_hex(16)}{datetime.now().timestamp()}".encode()
        ).hexdigest()[:20]
    
    def create_account(self, account_id: str, initial_balance: float = 0.0, currency: str = "USD") -> bool:
        if not self._validate_account_id(account_id):
            self._logger.error("Invalid account ID")
            return False
            
        if not self._validate_amount(initial_balance):
            self._logger.error("Invalid initial balance")
            return False
            
        if account_id in self.accounts:
            self._logger.warning(f"Account {account_id} already exists")
            return False
            
        self.accounts[account_id] = Account(
            account_id=account_id,
            balance=initial_balance,
            currency=currency,
            created_at=datetime.now()
        )
        self._logger.info(f"Created account {account_id} with balance {initial_balance}")
        return True
    
    def process_transaction(self, account_id: str, amount: float, transaction_type: str, description: str = "") -> Tuple[bool, str]:
        if not self._validate_account_id(account_id):
            return False, "Invalid account ID"
            
        if not self._validate_amount(amount):
            return False, "Invalid transaction amount"
            
        if not self._validate_transaction_type(transaction_type):
            return False, "Invalid transaction type"
            
        if account_id not in self.accounts:
            return False, "Account not found"
            
        account = self.accounts[account_id]
        
        try:
            transaction_id = self._generate_transaction_id()
            timestamp = datetime.now()
            
            if transaction_type.lower() == 'debit':
                if account.balance < amount:
                    return False, "Insufficient funds"
                account.balance -= amount
            else:  # credit
                account.balance += amount
                
            transaction = Transaction(
                transaction_id=transaction_id,
                account_id=account_id,
                amount=amount,
                transaction_type=transaction_type,
                timestamp=timestamp,
                description=description
            )
            
            self.transactions.append(transaction)
            self._logger.info(f"Processed {transaction_type} transaction for {account_id}: {amount}")
            return True, f"Transaction successful. New balance: {account.balance}"
            
        except Exception as e:
            self._logger.error(f"Transaction processing error: {str(e)}")
            return False, "Transaction processing failed"
    
    def get_account_balance(self, account_id: str) -> Tuple[bool, float]:
        if not self._validate_account_id(account_id):
            return False, 0.0
            
        if account_id not in self.accounts:
            return False, 0.0
            
        return True, self.accounts[account_id].balance
    
    def get_account_info(self, account_id: str) -> Tuple[bool, Account]:
        if not self._validate_account_id(account_id):
            return False, None
            
        if account_id not in self.accounts:
            return False, None
            
        return True, self.accounts[account_id]
    
    def get_transaction_history(self, account_id: str) -> List[Transaction]:
        if not self._validate_account_id(account_id):
            return []
            
        return [t for t in self.transactions if t.account_id == account_id]
    
    def get_all_accounts(self) -> Dict[str, Account]:
        return self.accounts.copy()
    
    def transfer_funds(self, from_account_id: str, to_account_id: str, amount: float, description: str = "") -> Tuple[bool, str]:
        if not self._validate_account_id(from_account_id) or not self._validate_account_id(to_account_id):
            return False, "Invalid account IDs"
            
        if from_account_id == to_account_id:
            return False, "Cannot transfer to same account"
            
        if not self._validate_amount(amount):
            return False, "Invalid transfer amount"
            
        # Check if source account has sufficient funds
        success, balance = self.get_account_balance(from_account_id)
        if not success or balance < amount:
            return False, "Insufficient funds for transfer"
            
        # Process debit from source account
        success, msg = self.process_transaction(
            from_account_id, amount, 'debit', f"Transfer to {to_account_id}: {description}"
        )
        if not success:
            return False, f"Transfer failed: {msg}"
            
        # Process credit to destination account
        success, msg = self.process_transaction(
            to_account_id, amount, 'credit', f"Transfer from {from_account_id}: {description}"
        )
        if not success:
            # Rollback debit if credit fails
            self.process_transaction(
                from_account_id, amount, 'credit', f"Transfer rollback: {description}"
            )
            return False, f"Transfer failed: {msg}"
            
        return True, f"Transfer successful. Amount: {amount}"